queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?newspapers a :Newspapers .
    ?newspapers p:name ?name .
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?magazines a :Magazines .
    ?magazines p:name ?name .
    ?magazines p:Circulation_Numbers ?circulation_numbers_f .
    FILTER((STR(?circulation_numbers_f) = "20000" || STR(?circulation_numbers_f) = "20000.0"))
    BIND(?name AS ?o0)
  }
}

